class Solution(object):
    def sortMatrix(self, grid):
        from collections import defaultdict
        n = len(grid)
        diags = defaultdict(list)

        for i in range(n):
            for j in range(n):
                diags[i - j].append(grid[i][j])

        # Sort: bottom-left triangle (i-j >= 0) non-increasing; top-right (i-j < 0) non-decreasing
        for key in diags:
            if key >= 0:
                diags[key].sort(reverse=True)
            else:
                diags[key].sort()

        # Refill: diagonals go from top-left to bottom-right
        # For key = i-j, the diagonal cells are visited in order of increasing i (and j)
        # We need to assign sorted values back in the same top-to-bottom traversal order
        idx = defaultdict(int)
        for i in range(n):
            for j in range(n):
                key = i - j
                grid[i][j] = diags[key][idx[key]]
                idx[key] += 1

        return grid
